self.addEventListener("push",t=>{if(!t.data)return;let i={title:"Handify"};try{i=t.data.json()}catch{i={title:t.data.text()}}t.waitUntil(self.registration.showNotification(i.title,{body:i.body??"",icon:"/icons/icon-192x192.png",badge:"/icons/icon-192x192.png",data:{link:i.link??"/"},vibrate:[200,100,200]}))}),self.addEventListener("notificationclick",t=>{t.notification.close();let i=t.notification.data?.link??"/";t.waitUntil(self.clients.matchAll({type:"window",includeUncontrolled:!0}).then(t=>{for(let n of t)if("focus"in n)return n.navigate(i),n.focus();return self.clients.openWindow(i)}))});